local TD_BAK = TD local TD = TD_BAK.td1madao["ydj_dst_td1madao"] TD.createFn("null", function() local inst = _G.CreateEntity() inst.entity:AddTransform() inst:DoTaskInTime(1, function() TD.remove(inst) end) inst:AddTag("nil") inst.persists = false return inst end) TD.createFn("longNull", function() local inst = _G.CreateEntity() inst.entity:AddTransform() inst:DoTaskInTime(30, function() TD.remove(inst) end) inst:AddTag("nil") inst.persists = false return inst end) TD.createFn("nilweapon", function() local inst = _G.CreateEntity() inst.entity:AddTransform() inst:AddTag("nilweapon") inst.persists = false TD.server(function() TD.addC(inst, "weapon", function(comp) comp:SetDamage(10) end) end) return inst end) TD.createFn("zf", function() local n = math.random(2) - 1 if n == 0 then n = -1 end return n end) TD.createFn("pointValid", function(x, y, z) local ground = TD.GetWorld() local tile = ground.Map:GetTileAtPoint(x, y, z) local validposition = (tile ~= _G.GROUND.IMPASSABLE) if not validposition then return false end return true end) TD.createFn("td1madao_isvalidposition", function(x, y, z, structure, inst) if not (TD.pointValid(x, 0, z) and TD.pointValid(x + 3, 0, z) and TD.pointValid(x - 3, 0, z) and TD.pointValid(x, 0, z - 3) and TD.pointValid(x, 0, z + 3)) then return false end local ents = TheSim:FindEntities(x, y, z, structure or 1) for k, v in pairs(ents) do if v and v ~= inst and v.components and (v:HasTag("structure") or v.components.workable or v.components.locomotor) then return false end end return true end) TD.createFn("around", function(target, dist) local x2, y2, z2 = target.Transform:GetWorldPosition() local ents = TheSim:FindEntities(x2, y2, z2, dist) return ents end) TD.createFn("td1madao_forcespawnAround", function(inst, name, distance) if not inst or not inst.Transform then return end if not distance then distance = 2 end local x0, y0, z0 = inst.Transform:GetWorldPosition() for i = 1, 100 do local calcx = x0 - (math.random(distance) * TD.zf()) local calcy = 0 local calcz = z0 - (math.random(distance) * TD.zf()) if TD.td1madao_isvalidposition(calcx, calcy, calcz) then local item = TD.spawn(name) item.Transform:SetPosition(calcx, calcy, calcz) return item end end end) TD.createFn("spawnFxAround", function(inst, name, distance) if not inst or not inst.Transform then return end if not distance then distance = 2 end local x0, y0, z0 = inst.Transform:GetWorldPosition() local calcx = x0 - (distance * TD.zf() + math.random(distance) * TD.zf()) local calcy = 0 local calcz = z0 - (distance * TD.zf() + math.random(distance) * TD.zf()) local item = TD.spawn(name) item.Transform:SetPosition(calcx, calcy, calcz) return item end) TD.createFn("spawn", function(name) local elem if string.td1madao_notEmpty(name) and _G.Prefabs[name] then elem = _G.SpawnPrefab(name) else elem = TD.null() end return elem end) TD.createFn("prefabAlias", function(aliasName, prefabName, fn) if not TD.isStr(aliasName) or not TD.isStr(prefabName) then return end local newAlias = "prefab_" .. aliasName local switch = TD.G[newAlias] if TD.isStr(switch) then  return TD.G[newAlias] end TD.G[newAlias] = prefabName if TD.isFn(fn) then  fn(prefabName) end return prefabName end) TD.createFn("spawnAlias", function(aliasName) if not TD.isStr(aliasName) then return end local newAlias = "prefab_" .. aliasName local switch = TD.G[newAlias] if TD.isStr(switch) then return TD.spawn(switch) end return TD.null() end) TD.createFn("belowAlias", function(inst, aliasName) if not TD.isStr(aliasName) then return end local newAlias = "prefab_" .. aliasName local switch = TD.G[newAlias] if TD.isStr(switch) then return TD.below(inst, aliasName) end return TD.null() end) TD.createFn("remove", function(inst) if not inst then return end if inst.components and inst.components.health then  TD.hide(inst)  if inst.components.lootdropper and inst.components.lootdropper.SetLoot then  inst:RemoveComponent("lootdropper") TD.addC(inst, "lootdropper") end  inst:AddTag("will_remove") inst.components.health:Kill() elseif inst.Remove then  inst:Remove() end end) TD.createFn("removeAfter", function(inst, time) if not inst then return nil end TD.latter(inst, time or 1, function() TD.remove(inst) end) return inst end) TD.createFn("hide", function(inst) if not inst or not inst.Hide then return end inst:Hide() return inst end) TD.createFn("show", function(inst) if not inst or not inst.Show then return end inst:Show() return inst end) TD.createFn("removeElem", function(inst, name) if not inst or not TD.isStr(name) or inst[name] == nil then return end if inst[name].Remove then TD.remove(inst[name]) end inst[name] = nil end) TD.createFn("removeElemAfter", function(inst, name, time) if not inst or not TD.isStr(name) then return end TD.latter(inst, time or 1, function() if not inst or not TD.isStr(name) or inst[name] == nil then return end if inst[name].Remove then TD.remove(inst[name]) end inst[name] = nil end) return inst[name] end) TD.createFn("below", function(inst, itemName) if not inst or not TD.valid(inst) then return TD.null() end local tmp = TD.spawn(itemName) if tmp and tmp.Transform and tmp.Transform.SetPosition and inst and inst.GetPosition then TD.pos_s(tmp, TD.pos_g(inst)) end if tmp and tmp.Show then tmp:Show() end return tmp end) TD.createFn("belowy", function(inst, itemName) if not inst or not TD.valid(inst) then return TD.null() end local tmp = TD.spawn(itemName) if tmp and tmp.Transform and tmp.Transform.SetPosition and inst and inst.GetPosition then local x, y, z = TD.pos_g(inst) TD.pos_s(tmp, x, 0, z) end if tmp and tmp.Show then tmp:Show() end return tmp end) TD.createFn("pChild", function(inst, itemName) if not inst or not TD.valid(inst) then return TD.null() end TD.server(function() TD.removeElem(inst, itemName) inst[itemName] = TD.child(inst, itemName) end) return inst[itemName] end) TD.createFn("child", function(inst, itemName) if not inst or not TD.valid(inst) then return TD.null() end local tmp = TD.spawn(itemName) if tmp and tmp.entity and inst.entity then tmp.entity:SetParent(inst.entity) end return tmp end) TD.createFn("prefab", function(ch, en, name, fn, ...) if not _G.Prefabs or _G.Prefabs[name] ~= nil then return nil end ch = ch or name en = en or name if not TD.isStr(ch) then ch = "nil" end if not TD.isStr(en) then en = "nil" end if TD.isCh() then TD.lang(name, ch) else TD.lang(name, en) end local prefabTab = TD.default(TD.G, TD.CONST.PREFAB_ALL) local obj = TD.default(prefabTab, name) obj.ch = ch obj.en = en return _G.Prefab(name, fn, ...) end) TD.createFn("prefab2", function(ch, ch2, name, fn, ...) if not _G.Prefabs or _G.Prefabs[name] ~= nil then return nil end ch = ch or name ch2 = ch2 or name if not TD.isStr(ch) then ch = "nil" end if not TD.isStr(ch2) then ch2 = "nil" end TD.lang2(name, ch , ch2) local prefabTab = TD.default(TD.G, TD.CONST.PREFAB_ALL) local obj = TD.default(prefabTab, name) obj.ch = ch obj.en = ch obj.ch2 = ch2 return _G.Prefab(name, fn, ...) end) TD.createFn("recipe", function(name, tab, icon, xml, tech) if not _G.AllRecipes or _G.AllRecipes[name] ~= nil then return _G.AllRecipes[name] end return AddRecipe(name, tab, _G.RECIPETABS[TD.up(TD.CHAR)], tech or _G.TECH.NONE, nil, nil, nil, nil, TD.CHAR, xml or "images/inventoryimages.xml", icon or string.format("%s.tex", name)) end) TD.createFn("recipeAll", function(name, tab, icon, xml, tech) if not _G.AllRecipes or _G.AllRecipes[name] ~= nil then return _G.AllRecipes[name] end return AddRecipe(name, tab, _G.RECIPETABS[TD.up(TD.CHAR)], tech or _G.TECH.NONE, nil, nil, nil, nil, nil, xml or "images/inventoryimages.xml", icon or string.format("%s.tex", name)) end) TD.createFn("basicPlayerResource", function() return { _G.Asset("ANIM", "anim/player_basic.zip"), _G.Asset("ANIM", "anim/player_idles_shiver.zip"), _G.Asset("ANIM", "anim/player_actions.zip"), _G.Asset("ANIM", "anim/player_actions_axe.zip"), _G.Asset("ANIM", "anim/player_actions_pickaxe.zip"), _G.Asset("ANIM", "anim/player_actions_shovel.zip"), _G.Asset("ANIM", 